const provider = 'gemini';

function extractJson(input) {
  const raw = String(input || '').trim();
  if (!raw) return null;

  const cleaned = raw
    .replace(/^```json/i, '')
    .replace(/^```/i, '')
    .replace(/```$/i, '')
    .trim();

  try {
    return JSON.parse(cleaned);
  } catch {
    const match = cleaned.match(/\{[\s\S]*\}/);
    if (!match) return null;

    try {
      return JSON.parse(match[0]);
    } catch {
      return null;
    }
  }
}

function cleanUrl(value) {
  const url = String(value || '').trim();
  if (!url) return '';
  if (!/^https?:\/\//i.test(url)) return '';
  return url;
}

const prepared = $('Prepare Web Search Prompt').first().json;
const parsed = extractJson($json.output || $json.text || $json.response || $json.content || '');

const maxResults = Number(prepared.maxResults || 5);

const results = Array.isArray(parsed?.results)
  ? parsed.results
      .map((item) => {
        const url = cleanUrl(item?.url);
        return {
          title: String(item?.title || '').replace(/\s+/g, ' ').trim(),
          url,
          snippet: String(item?.snippet || '').replace(/\s+/g, ' ').trim(),
          sourceType: 'website'
        };
      })
      .filter((item) => item.title && item.url)
      .slice(0, maxResults)
  : [];

return [{
  json: {
    success: results.length > 0,
    provider,
    fallback: false,
    query: String(parsed?.query || prepared.query || '').trim(),
    results,
    message: results.length
      ? `Found ${results.length} web source suggestions.`
      : 'Gemini did not return usable web source suggestions.'
  }
}];

